import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("returns 5G for an empty item list (processing fee only)");
    it.todo("returns 105G for a single sword (100G base + 5G fee)");
    it.todo("returns 65G for a single amulet (60G base + 5G fee)");
    it.todo("returns 85G for a single staff (80G base + 5G fee)");
    it.todo("returns 45G for a single potion (40G base + 5G fee)");
    it.todo("returns 165G for a sword and an amulet (100+60 base + 5G fee)");
  });

  describe("Quote - component premiums", () => {
    it.todo("returns 30G for a single rune (25G base + 5G fee)");
    it.todo("returns 55G for 2 runes (50G base + 5G fee)");
    it.todo("returns 65G for 3 runes (60G block discount + 5G fee)");
    it.todo("returns 105G for 4 runes (no block, 100G base + 5G fee)");
    it.todo("returns 180G for 7 runes (175G base + 5G fee)");
    it.todo("returns 80G for 2 runes and 1 moonstone (75G, no block, + 5G fee)");
    it.todo("returns 125G for 3 runes and 3 moonstones (two blocks, 120G + 5G fee)");
  });

  describe("Quote - cursed surcharge", () => {
    it.todo("adds 50% surcharge to a cursed sword (100+50 base + 5G fee = 155G)");
    it.todo("applies curse surcharge only to the cursed item in a multi-item policy");
  });

  describe("Quote - high enchantment surcharge", () => {
    it.todo("adds 30% surcharge for enchantment level 5 (threshold)");
    it.todo("does not add surcharge for enchantment level 4");
    it.todo("applies both cursed and high enchantment surcharges to same item");
  });

  describe("Quote - first insurance surcharge", () => {
    it.todo("adds 10% first insurance surcharge to policy base premium");
    it.todo("applies first insurance surcharge to every quote regardless of customer history");
  });

  describe("Quote - loyalty discount", () => {
    it.todo("applies 20% loyalty discount for customer with 2 years (threshold)");
    it.todo("does not apply loyalty discount for customer with 1 year");
  });

  describe("Quote - follow-up contract discount", () => {
    it.todo("applies 15% discount on second quote in scenario");
    it.todo("does not apply discount on first quote in scenario");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO favor (ceiling)");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 0 years, first contract = 165G");
    it.todo("long-standing customer second contract: cursed sword ench 7 = 160G");
  });

  describe("Quote - errors", () => {
    it.todo("rejects unknown item type with non-zero exit");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a regular item");
    it.todo("reimburses damage to a component minus 100G deductible");
  });

  describe("Claim - deductible per item", () => {
    it.todo("applies deductible separately to each damaged item in same event");
  });

  describe("Claim - high enchantment reimbursement", () => {
    it.todo("reimburses 50% of damage then deductible for enchantment >= 8");
  });

  describe("Claim - dragon material reimbursement", () => {
    it.todo("reimburses full damage then deductible for dragon material item");
  });

  describe("Claim - dragon material + high enchantment", () => {
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("applies full reimbursement for dragon material with enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across multiple claims on same policy");
    it.todo("insurance sum uses unmodified item values, not premiums");
    it.todo("component block discount does not affect insurance sum");
  });

  describe("Claim - multiple items of same type", () => {
    it.todo("treats each damage entry separately with its own deductible");
    it.todo("rejects claim with more damages of a type than policy covers");
  });

  describe("Claim - errors", () => {
    it.todo("rejects damage to item not covered by policy");
    it.todo("rejects negative damage amount");
  });
});

