const PROCESSING_FEE = 5;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const isComponent = (type: string): boolean => !MAIN_ITEM_PREMIUMS.hasOwnProperty(type);

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;

const calculateMainItemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
  let premium = base;
  if (item.cursed) {
    premium += base * CURSED_SURCHARGE_RATE;
  }
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return premium;
};

const calculateComponentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;

const calculateBasePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[]): number => {
  let total = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += calculateMainItemPremium(item);
    }
  }

  for (const count of Object.values(componentCounts)) {
    total += calculateComponentGroupPremium(count);
  }

  return total;
};

export function processScenario(scenario: { steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    const premium = calculateBasePremium(step.items ?? []) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

