import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5G for an empty item list (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("returns 105G for a single sword (100G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("returns 65G for a single amulet (60G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("returns 85G for a single staff (80G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "oak", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 85 });
    });
    it("returns 45G for a single potion (40G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 45 });
    });
    it("returns 165G for a sword and an amulet (100+60 base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 165 });
    });
  });

  describe("Quote - component premiums", () => {
    it("returns 30G for a single rune (25G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 30 });
    });
    it("returns 55G for 2 runes (50G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 55 });
    });
    it("returns 65G for 3 runes (60G block discount + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("returns 105G for 4 runes (no block, 100G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("returns 180G for 7 runes (175G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: Array.from({ length: 7 }, () => ({ type: "rune" })),
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 180 });
    });
    it("returns 80G for 2 runes and 1 moonstone (75G, no block, + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 80 });
    });
    it("returns 125G for 3 runes and 3 moonstones (two blocks, 120G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
              { type: "moonstone" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 125 });
    });
  });

  describe("Quote - cursed surcharge", () => {
    it("adds 50% surcharge to a cursed sword (100+50 base + 5G fee = 155G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 155 });
    });
    it("applies curse surcharge only to the cursed item in a multi-item policy", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 100 base sword + 50 curse + 60 base amulet = 210 + 5 fee = 215
      expect(result.results[0]).toEqual({ premium: 215 });
    });
  });

  describe("Quote - high enchantment surcharge", () => {
    it("adds 30% surcharge for enchantment level 5 (threshold)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      // 100 base + 30 enchantment surcharge = 130 + 5 fee = 135
      expect(result.results[0]).toEqual({ premium: 135 });
    });
    it("does not add surcharge for enchantment level 4", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 4, cursed: false },
            ],
          },
        ],
      });
      // 100 base only, no enchantment surcharge + 5 fee = 105
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("applies both cursed and high enchantment surcharges to same item", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: true },
            ],
          },
        ],
      });
      // 100 base + 50 curse + 30 enchantment = 180 + 5 fee = 185
      expect(result.results[0]).toEqual({ premium: 185 });
    });
  });

  describe("Quote - first insurance surcharge", () => {
    it("adds 10% first insurance surcharge to policy base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 100 base + 10 first insurance (10% of 100) + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("applies first insurance surcharge to every quote regardless of customer history");
  });

  describe("Quote - loyalty discount", () => {
    it.todo("applies 20% loyalty discount for customer with 2 years (threshold)");
    it.todo("does not apply loyalty discount for customer with 1 year");
  });

  describe("Quote - follow-up contract discount", () => {
    it.todo("applies 15% discount on second quote in scenario");
    it.todo("does not apply discount on first quote in scenario");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO favor (ceiling)");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 0 years, first contract = 165G");
    it.todo("long-standing customer second contract: cursed sword ench 7 = 160G");
  });

  describe("Quote - errors", () => {
    it.todo("rejects unknown item type with non-zero exit");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a regular item");
    it.todo("reimburses damage to a component minus 100G deductible");
  });

  describe("Claim - deductible per item", () => {
    it.todo("applies deductible separately to each damaged item in same event");
  });

  describe("Claim - high enchantment reimbursement", () => {
    it.todo("reimburses 50% of damage then deductible for enchantment >= 8");
  });

  describe("Claim - dragon material reimbursement", () => {
    it.todo("reimburses full damage then deductible for dragon material item");
  });

  describe("Claim - dragon material + high enchantment", () => {
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("applies full reimbursement for dragon material with enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across multiple claims on same policy");
    it.todo("insurance sum uses unmodified item values, not premiums");
    it.todo("component block discount does not affect insurance sum");
  });

  describe("Claim - multiple items of same type", () => {
    it.todo("treats each damage entry separately with its own deductible");
    it.todo("rejects claim with more damages of a type than policy covers");
  });

  describe("Claim - errors", () => {
    it.todo("rejects damage to item not covered by policy");
    it.todo("rejects negative damage amount");
  });
});

